// =============================================================================
// Environment Configuration
// =============================================================================

type Environment string

const (
	EnvDevelopment Environment = "development"
	EnvStaging     Environment = "staging"
	EnvProduction  Environment = "production"
)

type ServerConfig struct {
	Environment       Environment
	Port              int
	TLSCertFile       string
	TLSKeyFile        string
	TLSCAFile         string
	ReflectionEnabled bool
	AllowedCIDRs      []string
	APIKeys           map[string]string // key -> description
	RateLimitPerSec   int
}

func LoadConfig() *ServerConfig {
	env := Environment(getEnvOrDefault("APP_ENV", "development"))
	reflectionEnabled := getEnvOrDefault("GRPC_REFLECTION_ENABLED", "false") == "true"

	// In production, NEVER enable reflection regardless of env var
	if env == EnvProduction {
		reflectionEnabled = false
		log.Println("SECURITY: gRPC reflection is DISABLED in production environment")
	}

	config := &ServerConfig{
		Environment:       env,
		Port:              50051,
		TLSCertFile:       getEnvOrDefault("TLS_CERT_FILE", "certs/server.crt"),
		TLSKeyFile:        getEnvOrDefault("TLS_KEY_FILE", "certs/server.key"),
		TLSCAFile:         getEnvOrDefault("TLS_CA_FILE", "certs/ca.crt"),
		ReflectionEnabled: reflectionEnabled,
		AllowedCIDRs:      strings.Split(getEnvOrDefault("ALLOWED_CIDRS", "127.0.0.1/32,10.0.0.0/8"), ","),
		APIKeys:           loadAPIKeys(),
		RateLimitPerSec:   10,
	}

	return config
}

func getEnvOrDefault(key, defaultVal string) string {
	if val := os.Getenv(key); val != "" {
		return val
	}
	return defaultVal
}

func loadAPIKeys() map[string]string {
	keys := make(map[string]string)
	// In production, load from a secure vault (e.g., HashiCorp Vault, AWS Secrets Manager)
	// For development, use environment variables
	if apiKey := os.Getenv("DEV_API_KEY"); apiKey != "" {
		keys[apiKey] = "development-key"
	}
	// Default dev key (only for local development)
	if os.Getenv("APP_ENV") == "development" {
		keys["dev-only-key-not-for-production"] = "local-dev"
	}
	return keys
}

// =============================================================================
// Rate Limiter
// =============================================================================

type RateLimiter struct {
	mu       sync.Mutex
	requests map[string][]time.Time
	limit    int
	window   time.Duration
}

func NewRateLimiter(limitPerSec int) *RateLimiter {
	return &RateLimiter{
		requests: make(map[string][]time.Time),
		limit:    limitPerSec,
		window:   time.Second,
	}
}

func (rl *RateLimiter) Allow(clientID string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	now := time.Now()
	cutoff := now.Add(-rl.window)

	// Clean old entries
	if times, ok := rl.requests[clientID]; ok {
		var valid []time.Time
		for _, t := range times {
			if t.After(cutoff) {
				valid = append(valid, t)
			}
		}
		rl.requests[clientID] = valid
	}

	if len(rl.requests[clientID]) >= rl.limit {
		return false
	}

	rl.requests[clientID] = append(rl.requests[clientID], now)
	return true
}

