// Security Interceptors
// =============================================================================

type SecurityInterceptor struct {
	config      *ServerConfig
	rateLimiter *RateLimiter
}

func NewSecurityInterceptor(config *ServerConfig) *SecurityInterceptor {
	return &SecurityInterceptor{
		config:      config,
		rateLimiter: NewRateLimiter(config.RateLimitPerSec),
	}
}

// reflectionGuardUnary blocks reflection calls unless explicitly allowed
func (si *SecurityInterceptor) reflectionGuardUnary(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	// Check if this is a reflection request
	if isReflectionMethod(info.FullMethod) {
		if err := si.authorizeReflection(ctx); err != nil {
			return nil, err
		}
	}

	// Rate limiting
	clientID := extractClientID(ctx)
	if !si.rateLimiter.Allow(clientID) {
		return nil, status.Errorf(codes.ResourceExhausted, "rate limit exceeded")
	}

	// Authentication for all requests
	if err := si.authenticate(ctx, info.FullMethod); err != nil {
		return nil, err
	}

	return handler(ctx, req)
}

// reflectionGuardStream blocks reflection stream calls unless explicitly allowed
func (si *SecurityInterceptor) reflectionGuardStream(
	srv interface{},
	ss grpc.ServerStream,
	info *grpc.StreamServerInfo,
	handler grpc.StreamHandler,
) error {
	if isReflectionMethod(info.FullMethod) {
		if err := si.authorizeReflection(ss.Context()); err != nil {
			return err
		}
	}

	clientID := extractClientID(ss.Context())
	if !si.rateLimiter.Allow(clientID) {
		return status.Errorf(codes.ResourceExhausted, "rate limit exceeded")
	}

	if err := si.authenticate(ss.Context(), info.FullMethod); err != nil {
		return err
	}

	return handler(srv, ss)
}

func isReflectionMethod(fullMethod string) bool {
	return strings.HasPrefix(fullMethod, "/grpc.reflection.")
}

func (si *SecurityInterceptor) authorizeReflection(ctx context.Context) error {
	// In production, reflection is completely disabled
	if si.config.Environment == EnvProduction {
		log.Println("SECURITY ALERT: Reflection request blocked in production")
		return status.Errorf(codes.PermissionDenied, "reflection is not available")
	}

	// Even in dev/staging, require authentication and IP allowlisting
	if !si.config.ReflectionEnabled {
		return status.Errorf(codes.PermissionDenied, "reflection is disabled")
	}

	// Verify the client IP is in the allowed CIDR range
	if err := si.verifyClientIP(ctx); err != nil {
		log.Printf("SECURITY: Reflection request from unauthorized IP: %v", err)
		return status.Errorf(codes.PermissionDenied, "unauthorized source IP for reflection")
	}

	// Require valid API key for reflection
	if err := si.verifyAPIKey(ctx); err != nil {
		log.Printf("SECURITY: Reflection request with invalid API key: %v", err)
		return status.Errorf(codes.Unauthenticated, "valid API key required for reflection")
	}

	log.Println("AUDIT: Reflection request authorized for development use")
	return nil
}

func (si *SecurityInterceptor) authenticate(ctx context.Context, method string) error {
	// Health checks can be unauthenticated
	if strings.HasSuffix(method, "/Check") || strings.HasSuffix(method, "/Watch") {
		return nil
	}

	return si.verifyAPIKey(ctx)
}

func (si *SecurityInterceptor) verifyAPIKey(ctx context.Context) error {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return status.Errorf(codes.Unauthenticated, "missing metadata")
	}

	apiKeys := md.Get("x-api-key")
	if len(apiKeys) == 0 {
		return status.Errorf(codes.Unauthenticated, "missing API key")
	}

	apiKey := apiKeys[0]
	if _, valid := si.config.APIKeys[apiKey]; !valid {
		return status.Errorf(codes.Unauthenticated, "invalid API key")
	}

	return nil
}

func (si *SecurityInterceptor) verifyClientIP(ctx context.Context) error {
	p, ok := peer.FromContext(ctx)
	if !ok {
		return fmt.Errorf("unable to extract peer information")
	}

	clientAddr := p.Addr.String()
	clientIP := clientAddr
	if host, _, err := net.SplitHostPort(clientAddr); err == nil {
		clientIP = host
	}

	ip := net.ParseIP(clientIP)
	if ip == nil {
		return fmt.Errorf("invalid client IP: %s", clientIP)
	}

	for _, cidr := range si.config.AllowedCIDRs {
		cidr = strings.TrimSpace(cidr)
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return nil
		}
	}

	return fmt.Errorf("client IP %s not in allowed CIDRs", clientIP)
}

func extractClientID(ctx context.Context) string {
	p, ok := peer.FromContext(ctx)
	if !ok {
		return "unknown"
	}
	return p.Addr.String()
}

// =============================================================================
// Audit Logger Interceptor
// =============================================================================

func auditLogUnary(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	start := time.Now()
	clientID := extractClientID(ctx)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	statusCode := codes.OK
	if err != nil {
		statusCode = status.Code(err)
	}

	log.Printf("AUDIT: method=%s client=%s status=%s duration=%v",
		info.FullMethod, clientID, statusCode, duration)

	if isReflectionMethod(info.FullMethod) {
		log.Printf("AUDIT: REFLECTION access by client=%s status=%s", clientID, statusCode)
	}

	return resp, err
}

func auditLogStream(
	srv interface{},
	ss grpc.ServerStream,
	info *grpc.StreamServerInfo,
	handler grpc.StreamHandler,
) error {
	start := time.Now()
	clientID := extractClientID(ss.Context())

	err := handler(srv, ss)

	duration := time.Since(start)
	statusCode := codes.OK
	if err != nil {
		statusCode = status.Code(err)
	}

	log.Printf("AUDIT: stream method=%s client=%s status=%s duration=%v",
		info.FullMethod, clientID, statusCode, duration)

	return err
}

