type UserManagementService struct {
	mu    sync.RWMutex
	users map[string]*User
}

func NewUserManagementService() *UserManagementService {
	return &UserManagementService{
		users: make(map[string]*User),
	}
}

func (s *UserManagementService) CreateUser(ctx context.Context, req *CreateUserRequest) (*User, error) {
	if req.Email == "" || req.Name == "" {
		return nil, status.Errorf(codes.InvalidArgument, "email and name are required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Check for duplicate email
	for _, u := range s.users {
		if u.Email == req.Email {
			return nil, status.Errorf(codes.AlreadyExists, "user with email %s already exists", req.Email)
		}
	}

	id := fmt.Sprintf("user_%d", time.Now().UnixNano())
	now := timestamppb.Now()
	user := &User{
		Id:        id,
		Email:     req.Email,
		Name:      req.Name,
		CreatedAt: now,
		UpdatedAt: now,
	}
	s.users[id] = user

	log.Printf("User created: id=%s email=%s", id, req.Email)
	return user, nil
}

func (s *UserManagementService) GetUser(ctx context.Context, req *GetUserRequest) (*User, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "user ID is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	user, ok := s.users[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}

	return user, nil
}

func (s *UserManagementService) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*User, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "user ID is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	user, ok := s.users[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}

	if req.Email != "" {
		user.Email = req.Email
	}
	if req.Name != "" {
		user.Name = req.Name
	}
	user.UpdatedAt = timestamppb.Now()

	log.Printf("User updated: id=%s", req.Id)
	return user, nil
}

func (s *UserManagementService) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*emptypb.Empty, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "user ID is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.users[req.Id]; !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}

	delete(s.users, req.Id)
	log.Printf("User deleted: id=%s", req.Id)
	return &emptypb.Empty{}, nil
}

func (s *UserManagementService) ListUsers(ctx context.Context, req *ListUsersRequest) (*ListUsersResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	var users []*User
	for _, u := range s.users {
		users = append(users, u)
	}

	return &ListUsersResponse{
		Users:         users,
		NextPageToken: "",
	}, nil
}

