type OrderService struct {
	mu     sync.RWMutex
	orders map[string]*Order
}

func NewOrderService() *OrderService {
	return &OrderService{
		orders: make(map[string]*Order),
	}
}

func (s *OrderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	if req.UserId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "user ID is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Errorf(codes.InvalidArgument, "at least one item is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	var total float64
	for _, item := range req.Items {
		total += item.Price * float64(item.Quantity)
	}

	id := fmt.Sprintf("order_%d", time.Now().UnixNano())
	order := &Order{
		Id:        id,
		UserId:    req.UserId,
		Items:     req.Items,
		Total:     total,
		Status:    "PENDING",
		CreatedAt: timestamppb.Now(),
	}
	s.orders[id] = order

	log.Printf("Order created: id=%s user=%s total=%.2f", id, req.UserId, total)
	return order, nil
}

func (s *OrderService) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order ID is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	return order, nil
}

func (s *OrderService) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	var orders []*Order
	for _, o := range s.orders {
		if req.UserId == "" || o.UserId == req.UserId {
			orders = append(orders, o)
		}
	}

	return &ListOrdersResponse{
		Orders:        orders,
		NextPageToken: "",
	}, nil
}

func (s *OrderService) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order ID is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	if order.Status != "PENDING" {
		return nil, status.Errorf(codes.FailedPrecondition, "order %s cannot be cancelled (status: %s)", req.Id, order.Status)
	}

	order.Status = "CANCELLED"
	log.Printf("Order cancelled: id=%s", req.Id)
	return order, nil
}

