type PaymentService struct {
	mu       sync.RWMutex
	payments map[string]*Payment
}

func NewPaymentService() *PaymentService {
	return &PaymentService{
		payments: make(map[string]*Payment),
	}
}

func (s *PaymentService) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*Payment, error) {
	if req.OrderId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "order ID is required")
	}
	if req.Amount <= 0 {
		return nil, status.Errorf(codes.InvalidArgument, "amount must be positive")
	}
	if req.Currency == "" {
		return nil, status.Errorf(codes.InvalidArgument, "currency is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	id := fmt.Sprintf("pay_%d", time.Now().UnixNano())
	payment := &Payment{
		Id:        id,
		OrderId:   req.OrderId,
		Amount:    req.Amount,
		Currency:  req.Currency,
		Status:    "COMPLETED",
		CreatedAt: timestamppb.Now(),
	}
	s.payments[id] = payment

	log.Printf("Payment processed: id=%s order=%s amount=%.2f %s", id, req.OrderId, req.Amount, req.Currency)
	return payment, nil
}

func (s *PaymentService) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	if req.Id == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment ID is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	payment, ok := s.payments[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}

	return payment, nil
}

func (s *PaymentService) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*Payment, error) {
	if req.PaymentId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "payment ID is required")
	}
	if req.Reason == "" {
		return nil, status.Errorf(codes.InvalidArgument, "refund reason is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	payment, ok := s.payments[req.PaymentId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.PaymentId)
	}

	if payment.Status != "COMPLETED" {
		return nil, status.Errorf(codes.FailedPrecondition, "payment %s cannot be refunded (status: %s)", req.PaymentId, payment.Status)
	}

	if req.Amount > 0 && req.Amount <= payment.Amount {
		payment.Amount -= req.Amount
		if payment.Amount == 0 {
			payment.Status = "REFUNDED"
		} else {
			payment.Status = "PARTIALLY_REFUNDED"
		}
	} else {
		payment.Status = "REFUNDED"
		payment.Amount = 0
	}

	log.Printf("Payment refunded: id=%s reason=%s", req.PaymentId, req.Reason)
	return payment, nil
}

