// =============================================================================
// TLS Configuration
// =============================================================================

func loadTLSCredentials(config *ServerConfig) (credentials.TransportCredentials, error) {
	// For development without TLS certs, return nil (insecure)
	if config.Environment == EnvDevelopment {
		if _, err := os.Stat(config.TLSCertFile); os.IsNotExist(err) {
			log.Println("WARNING: Running without TLS in development mode")
			return nil, nil
		}
	}

	// Load server certificate and key
	serverCert, err := tls.LoadX509KeyPair(config.TLSCertFile, config.TLSKeyFile)
	if err != nil {
		return nil, fmt.Errorf("failed to load server certificate: %w", err)
	}

	tlsConfig := &tls.Config{
		Certificates: []tls.Certificate{serverCert},
		MinVersion:   tls.VersionTLS13,
	}

	// Load CA certificate for mutual TLS if available
	if config.TLSCAFile != "" {
		if _, err := os.Stat(config.TLSCAFile); err == nil {
			caCert, err := os.ReadFile(config.TLSCAFile)
			if err != nil {
				return nil, fmt.Errorf("failed to read CA certificate: %w", err)
			}

			certPool := x509.NewCertPool()
			if !certPool.AppendCertsFromPEM(caCert) {
				return nil, fmt.Errorf("failed to parse CA certificate")
			}

			tlsConfig.ClientCAs = certPool
			tlsConfig.ClientAuth = tls.RequireAndVerifyClientCert
			log.Println("Mutual TLS (mTLS) enabled")
		}
	}

	return credentials.NewTLS(tlsConfig), nil
}

// =============================================================================
// Main Server
// =============================================================================

func main() {
	config := LoadConfig()

	log.Printf("Starting gRPC server in %s environment", config.Environment)
	log.Printf("Reflection enabled: %v", config.ReflectionEnabled)

	// Build server options
	var serverOpts []grpc.ServerOption

	// TLS
	tlsCreds, err := loadTLSCredentials(config)
	if err != nil {
		log.Fatalf("Failed to load TLS credentials: %v", err)
	}
	if tlsCreds != nil {
		serverOpts = append(serverOpts, grpc.Creds(tlsCreds))
		log.Println("TLS enabled")
	}

	// Security interceptors
	securityInterceptor := NewSecurityInterceptor(config)

	// Chain interceptors: audit logging -> security checks
	serverOpts = append(serverOpts,
		grpc.ChainUnaryInterceptor(
			auditLogUnary,
			securityInterceptor.reflectionGuardUnary,
		),
		grpc.ChainStreamInterceptor(
			auditLogStream,
			securityInterceptor.reflectionGuardStream,
		),
		grpc.MaxRecvMsgSize(4*1024*1024), // 4MB max message size
		grpc.MaxSendMsgSize(4*1024*1024),
	)

	// Create gRPC server
	grpcServer := grpc.NewServer(serverOpts...)

	// Register services
	registrar := NewServiceRegistrar()
	registrar.RegisterAll(grpcServer)

	// Conditionally enable reflection with security controls
	// CRITICAL: Only enable in non-production environments with proper guards
	if config.ReflectionEnabled && config.Environment != EnvProduction {
		reflection.Register(grpcServer)
		log.Printf("WARNING: gRPC reflection is ENABLED for %s environment", config.Environment)
		log.Println("Reflection is protected by: IP allowlisting, API key authentication, rate limiting, and audit logging")
	} else {
		log.Println("gRPC reflection is DISABLED")
		if config.Environment == EnvProduction {
			log.Println("SECURITY: Reflection is always disabled in production regardless of configuration")
		}
	}

	// Start listening
	addr := fmt.Sprintf(":%d", config.Port)
	listener, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", addr, err)
	}

	log.Printf("gRPC server listening on %s", addr)
	log.Printf("Services registered: UserManagement, Orders, Payments")
	log.Printf("Security features: API key auth, IP allowlisting, rate limiting, audit logging")

	if err := grpcServer.Serve(listener); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}